import { useState, useRef, useEffect } from "react";

const GEMINI_API_URL = "https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent";

const SYSTEM_PROMPT = `You are NOVA — an intelligent AI assistant built as a college project. You support:
- General conversation and questions
- Student help (math, science, history, coding, essays)
- Healthcare info (symptoms, medicines, basic advice)
- E-commerce guidance (product recommendations, shopping help)
- Web searches (provide up-to-date info when asked)
- PDF/document analysis (when user describes content)
- Image analysis (describe what you see when images are shared)
- Hindi and English both (respond in whatever language user writes)
Always be helpful, friendly, and educational. If someone writes in Hindi, reply in Hindi.`;

const QUICK_PROMPTS = [
  { icon: "🎓", label: "College Help", text: "Mujhe machine learning concepts samjhao" },
  { icon: "🏥", label: "Health FAQ", text: "Headache ke liye kya karna chahiye?" },
  { icon: "🛒", label: "Shopping Bot", text: "Budget mein best laptop kaun sa hai?" },
  { icon: "💻", label: "Code Help", text: "Python mein sorting algorithms explain karo" },
  { icon: "🌐", label: "Current Info", text: "AI ke latest trends kya hain 2024 mein?" },
  { icon: "📝", label: "Essay Writer", text: "Climate change par ek short essay likho" },
];

function TypingIndicator() {
  return (
    <div style={{ display: "flex", gap: 5, alignItems: "center", padding: "12px 16px" }}>
      {[0, 1, 2].map(i => (
        <span key={i} style={{
          width: 8, height: 8, borderRadius: "50%", background: "#6366f1",
          animation: `bounce 1s ease-in-out ${i * 0.2}s infinite`
        }} />
      ))}
    </div>
  );
}

function Message({ msg }) {
  const isUser = msg.role === "user";
  return (
    <div style={{
      display: "flex", justifyContent: isUser ? "flex-end" : "flex-start",
      marginBottom: 16, animation: "fadeSlideIn 0.3s ease"
    }}>
      {!isUser && (
        <div style={{
          width: 36, height: 36, borderRadius: "50%",
          background: "linear-gradient(135deg, #6366f1, #8b5cf6)",
          display: "flex", alignItems: "center", justifyContent: "center",
          fontSize: 16, flexShrink: 0, marginRight: 10, marginTop: 2,
          boxShadow: "0 2px 8px rgba(99,102,241,0.4)"
        }}>🤖</div>
      )}
      <div style={{
        maxWidth: "75%",
        background: isUser
          ? "linear-gradient(135deg, #6366f1, #8b5cf6)"
          : "rgba(255,255,255,0.07)",
        color: isUser ? "#fff" : "#e2e8f0",
        borderRadius: isUser ? "18px 18px 4px 18px" : "18px 18px 18px 4px",
        padding: "12px 16px", fontSize: 14, lineHeight: 1.6,
        border: isUser ? "none" : "1px solid rgba(255,255,255,0.1)",
        whiteSpace: "pre-wrap", wordBreak: "break-word"
      }}>
        {msg.image && (
          <img src={msg.image} alt="uploaded"
            style={{ maxWidth: "100%", borderRadius: 8, marginBottom: 8, display: "block" }} />
        )}
        {msg.video && (
          <video src={msg.video} controls
            style={{ maxWidth: "100%", borderRadius: 8, marginBottom: 8, display: "block" }} />
        )}
        {msg.content}
        <div style={{ fontSize: 11, opacity: 0.6, marginTop: 4, textAlign: "right" }}>
          {msg.time}
        </div>
      </div>
      {isUser && (
        <div style={{
          width: 36, height: 36, borderRadius: "50%",
          background: "linear-gradient(135deg, #ec4899, #f43f5e)",
          display: "flex", alignItems: "center", justifyContent: "center",
          fontSize: 16, flexShrink: 0, marginLeft: 10, marginTop: 2
        }}>👤</div>
      )}
    </div>
  );
}

export default function App() {
  const [messages, setMessages] = useState([{
    role: "assistant",
    content: "Namaste! 🙏 Main NOVA hoon — aapka Smart AI Assistant.\n\nMain aapki help kar sakta hoon:\n• 🎓 Studies & Coding\n• 🏥 Health Questions\n• 🛒 Shopping Guidance\n• 🌐 Current Information\n• 📄 Document Analysis\n• 🖼️ Image & Video Analysis\n• 🎤 Voice Input & Output\n\nKuch bhi poochho — Hindi ya English mein! 😊",
    time: new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })
  }]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [history, setHistory] = useState([]);
  const [apiKey, setApiKey] = useState(localStorage.getItem("gemini_key") || "");
  const [showKeyInput, setShowKeyInput] = useState(!localStorage.getItem("gemini_key"));
  const [isListening, setIsListening] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [showCamera, setShowCamera] = useState(false);
  const [cameraStream, setCameraStream] = useState(null);
  const [voiceEnabled, setVoiceEnabled] = useState(true);

  const bottomRef = useRef(null);
  const inputRef = useRef(null);
  const fileInputRef = useRef(null);
  const videoFileRef = useRef(null);
  const videoRef = useRef(null);
  const recognitionRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, loading]);

  // ✅ Stop camera when closed
  useEffect(() => {
    if (!showCamera && cameraStream) {
      cameraStream.getTracks().forEach(t => t.stop());
      setCameraStream(null);
    }
  }, [showCamera]);

  const saveKey = () => {
    localStorage.setItem("gemini_key", apiKey);
    setShowKeyInput(false);
  };

  // ✅ TEXT TO SPEECH
  const speakText = (text) => {
    if (!voiceEnabled) return;
    window.speechSynthesis.cancel();
    const utter = new SpeechSynthesisUtterance(text);
    utter.lang = "hi-IN";
    utter.rate = 0.95;
    utter.pitch = 1;
    const voices = window.speechSynthesis.getVoices();
    const hindiVoice = voices.find(v => v.lang.includes("hi")) || voices[0];
    if (hindiVoice) utter.voice = hindiVoice;
    utter.onstart = () => setIsSpeaking(true);
    utter.onend = () => setIsSpeaking(false);
    window.speechSynthesis.speak(utter);
  };

  const stopSpeaking = () => {
    window.speechSynthesis.cancel();
    setIsSpeaking(false);
  };

  // ✅ VOICE INPUT
  const startListening = () => {
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SpeechRecognition) {
      alert("Tera browser voice input support nahi karta! Chrome use karo.");
      return;
    }
    const recognition = new SpeechRecognition();
    recognition.lang = "hi-IN";
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;
    recognition.onstart = () => setIsListening(true);
    recognition.onresult = (e) => {
      const transcript = e.results[0][0].transcript;
      setInput(transcript);
      setIsListening(false);
    };
    recognition.onerror = () => setIsListening(false);
    recognition.onend = () => setIsListening(false);
    recognitionRef.current = recognition;
    recognition.start();
  };

  const stopListening = () => {
    recognitionRef.current?.stop();
    setIsListening(false);
  };

  // ✅ IMAGE UPLOAD & SEND
  const handleImageUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = async (ev) => {
      const base64 = ev.target.result.split(",")[1];
      const imageUrl = ev.target.result;
      const time = new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
      const userMsg = { role: "user", content: "📷 Image bheja hai — analyze karo", image: imageUrl, time };
      setMessages(prev => [...prev, userMsg]);
      setLoading(true);
      const key = localStorage.getItem("gemini_key") || apiKey;
      try {
        const res = await fetch(`${GEMINI_API_URL}?key=${key}`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            contents: [{
              parts: [
                { text: "Is image ko analyze karo aur detail mein batao. Hindi ya English dono mein explain karo." },
                { inline_data: { mime_type: file.type, data: base64 } }
              ]
            }]
          })
        });
        const data = await res.json();
        const reply = data.candidates?.[0]?.content?.parts?.[0]?.text || "Image analyze nahi ho saki.";
        const assistantMsg = { role: "assistant", content: reply, time: new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }) };
        setMessages(prev => [...prev, assistantMsg]);
        speakText(reply.slice(0, 200));
      } catch (e) {
        setMessages(prev => [...prev, { role: "assistant", content: "❌ Image analyze karne mein error aaya.", time }]);
      }
      setLoading(false);
    };
    reader.readAsDataURL(file);
  };

  // ✅ VIDEO UPLOAD
  const handleVideoUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const url = URL.createObjectURL(file);
    const time = new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
    setMessages(prev => [...prev,
      { role: "user", content: "🎥 Video upload kiya", video: url, time },
      { role: "assistant", content: "Video upload ho gaya! ✅\n\nNote: Video playback ke liye dekh sakte ho. Deep video analysis ke liye Gemini 1.5 Pro API required hai.\n\nKya aap is video ke baare mein kuch poochna chahte ho?", time }
    ]);
  };

  // ✅ LIVE CAMERA
  const openCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true });
      setCameraStream(stream);
      setShowCamera(true);
      setTimeout(() => {
        if (videoRef.current) videoRef.current.srcObject = stream;
      }, 100);
    } catch (e) {
      alert("Camera access nahi mila! Browser settings mein camera allow karo.");
    }
  };

  const capturePhoto = () => {
    const canvas = document.createElement("canvas");
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    canvas.getContext("2d").drawImage(videoRef.current, 0, 0);
    const imageUrl = canvas.toDataURL("image/jpeg");
    const base64 = imageUrl.split(",")[1];
    const time = new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
    setShowCamera(false);
    setMessages(prev => [...prev, { role: "user", content: "📸 Live camera se photo li", image: imageUrl, time }]);
    setLoading(true);
    const key = localStorage.getItem("gemini_key") || apiKey;
    fetch(`${GEMINI_API_URL}?key=${key}`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        contents: [{
          parts: [
            { text: "Is captured image ko analyze karo. Hindi mein batao." },
            { inline_data: { mime_type: "image/jpeg", data: base64 } }
          ]
        }]
      })
    })
    .then(r => r.json())
    .then(data => {
      const reply = data.candidates?.[0]?.content?.parts?.[0]?.text || "Photo analyze nahi ho saki.";
      setMessages(prev => [...prev, { role: "assistant", content: reply, time: new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }) }]);
      speakText(reply.slice(0, 200));
      setLoading(false);
    })
    .catch(() => setLoading(false));
  };

  // ✅ SEND MESSAGE
  const sendMessage = async (text) => {
    const userText = text || input.trim();
    if (!userText) return;
    const key = localStorage.getItem("gemini_key") || apiKey;
    if (!key) { setShowKeyInput(true); return; }
    const time = new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
    const userMsg = { role: "user", content: userText, time };
    const newMessages = [...messages, userMsg];
    setMessages(newMessages);
    setInput("");
    setLoading(true);
    try {
      const conversationHistory = newMessages.slice(-10).map(m => ({
        role: m.role === "user" ? "user" : "model",
        parts: [{ text: m.content }]
      }));
      const res = await fetch(`${GEMINI_API_URL}?key=${key}`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          system_instruction: { parts: [{ text: SYSTEM_PROMPT }] },
          contents: conversationHistory,
          generationConfig: { temperature: 0.7, maxOutputTokens: 1024 }
        })
      });
      const data = await res.json();
      if (data.error) throw new Error(data.error.message);
      const reply = data.candidates?.[0]?.content?.parts?.[0]?.text || "Kuch error aaya.";
      const assistantMsg = { role: "assistant", content: reply, time: new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }) };
      setMessages(prev => [...prev, assistantMsg]);
      speakText(reply.slice(0, 300));
      if (!history.includes(userText.slice(0, 40))) {
        setHistory(prev => [userText.slice(0, 40), ...prev.slice(0, 9)]);
      }
    } catch (e) {
      setMessages(prev => [...prev, {
        role: "assistant",
        content: `❌ Error: ${e.message}`,
        time: new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })
      }]);
    }
    setLoading(false);
  };

  const handleKey = (e) => {
    if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); sendMessage(); }
  };

  return (
    <div style={{
      display: "flex", height: "100vh", fontFamily: "'Segoe UI', sans-serif",
      background: "#0f0f1a", color: "#e2e8f0", overflow: "hidden"
    }}>
      <style>{`
        @keyframes bounce { 0%,60%,100%{transform:translateY(0)} 30%{transform:translateY(-6px)} }
        @keyframes fadeSlideIn { from{opacity:0;transform:translateY(8px)} to{opacity:1;transform:translateY(0)} }
        @keyframes pulse { 0%,100%{opacity:1} 50%{opacity:0.4} }
        @keyframes ripple { 0%{transform:scale(1);opacity:1} 100%{transform:scale(1.8);opacity:0} }
        ::-webkit-scrollbar{width:4px} ::-webkit-scrollbar-track{background:transparent}
        ::-webkit-scrollbar-thumb{background:rgba(99,102,241,0.4);border-radius:4px}
        textarea:focus{outline:none!important}
        button:hover{opacity:0.85} button:active{transform:scale(0.97)}
      `}</style>

      {/* Hidden file inputs */}
      <input ref={fileInputRef} type="file" accept="image/*" style={{ display: "none" }} onChange={handleImageUpload} />
      <input ref={videoFileRef} type="file" accept="video/*" style={{ display: "none" }} onChange={handleVideoUpload} />

      {/* LIVE CAMERA MODAL */}
      {showCamera && (
        <div style={{
          position: "fixed", inset: 0, background: "rgba(0,0,0,0.85)",
          display: "flex", alignItems: "center", justifyContent: "center", zIndex: 200
        }}>
          <div style={{
            background: "#1e1e2e", borderRadius: 20, padding: 24,
            border: "1px solid rgba(99,102,241,0.4)", textAlign: "center"
          }}>
            <div style={{ fontSize: 18, fontWeight: 700, marginBottom: 16 }}>📷 Live Camera</div>
            <video ref={videoRef} autoPlay playsInline
              style={{ width: 400, borderRadius: 12, background: "#000" }} />
            <div style={{ display: "flex", gap: 12, marginTop: 16, justifyContent: "center" }}>
              <button onClick={capturePhoto} style={{
                background: "linear-gradient(135deg, #6366f1, #8b5cf6)",
                border: "none", borderRadius: 12, padding: "12px 28px",
                color: "#fff", fontWeight: 700, cursor: "pointer", fontSize: 15
              }}>📸 Photo Lo</button>
              <button onClick={() => setShowCamera(false)} style={{
                background: "rgba(255,255,255,0.08)",
                border: "1px solid rgba(255,255,255,0.15)", borderRadius: 12, padding: "12px 28px",
                color: "#94a3b8", cursor: "pointer", fontSize: 15
              }}>✕ Band Karo</button>
            </div>
          </div>
        </div>
      )}

      {/* SIDEBAR */}
      {sidebarOpen && (
        <div style={{
          width: 260, background: "rgba(255,255,255,0.04)",
          borderRight: "1px solid rgba(255,255,255,0.08)",
          display: "flex", flexDirection: "column", padding: "20px 16px"
        }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 28 }}>
            <div style={{
              width: 40, height: 40, borderRadius: 12,
              background: "linear-gradient(135deg, #6366f1, #8b5cf6)",
              display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20
            }}>🤖</div>
            <div>
              <div style={{ fontWeight: 700, fontSize: 16 }}>NOVA AI</div>
              <div style={{ fontSize: 12, color: "#64748b" }}>Smart Assistant</div>
            </div>
          </div>

          <button onClick={() => { setMessages([]); setHistory([]); }} style={{
            background: "linear-gradient(135deg, #6366f1, #8b5cf6)",
            border: "none", borderRadius: 10, padding: "10px 16px",
            color: "#fff", fontWeight: 600, cursor: "pointer", marginBottom: 20, fontSize: 13
          }}>+ New Chat</button>

          <div style={{ fontSize: 11, color: "#64748b", fontWeight: 600, letterSpacing: 1, marginBottom: 8 }}>QUICK PROMPTS</div>
          {QUICK_PROMPTS.map((qp, i) => (
            <button key={i} onClick={() => sendMessage(qp.text)} style={{
              background: "rgba(255,255,255,0.04)", border: "1px solid rgba(255,255,255,0.08)",
              borderRadius: 8, padding: "8px 12px", color: "#cbd5e1",
              cursor: "pointer", textAlign: "left", marginBottom: 4, fontSize: 12
            }}>{qp.icon} {qp.label}</button>
          ))}

          {history.length > 0 && <>
            <div style={{ fontSize: 11, color: "#64748b", fontWeight: 600, letterSpacing: 1, margin: "16px 0 8px" }}>HISTORY</div>
            {history.map((h, i) => (
              <div key={i} style={{
                fontSize: 12, color: "#94a3b8", padding: "6px 8px",
                borderRadius: 6, cursor: "pointer", overflow: "hidden",
                textOverflow: "ellipsis", whiteSpace: "nowrap"
              }}>💬 {h}...</div>
            ))}
          </>}

          <div style={{ marginTop: "auto" }}>
            {/* Voice Toggle */}
            <button onClick={() => setVoiceEnabled(!voiceEnabled)} style={{
              background: voiceEnabled ? "rgba(99,102,241,0.2)" : "transparent",
              border: `1px solid ${voiceEnabled ? "rgba(99,102,241,0.5)" : "rgba(255,255,255,0.1)"}`,
              borderRadius: 8, padding: "8px 12px", color: voiceEnabled ? "#a5b4fc" : "#64748b",
              cursor: "pointer", fontSize: 12, width: "100%", marginBottom: 8
            }}>{voiceEnabled ? "🔊 Voice ON" : "🔇 Voice OFF"}</button>

            <button onClick={() => setShowKeyInput(true)} style={{
              background: "transparent", border: "1px solid rgba(255,255,255,0.1)",
              borderRadius: 8, padding: "8px 12px", color: "#64748b",
              cursor: "pointer", fontSize: 12, width: "100%"
            }}>🔑 API Key Settings</button>
          </div>
        </div>
      )}

      {/* MAIN */}
      <div style={{ flex: 1, display: "flex", flexDirection: "column" }}>
        {/* Header */}
        <div style={{
          padding: "16px 24px", borderBottom: "1px solid rgba(255,255,255,0.08)",
          display: "flex", alignItems: "center", gap: 16,
          background: "rgba(255,255,255,0.02)"
        }}>
          <button onClick={() => setSidebarOpen(!sidebarOpen)} style={{
            background: "transparent", border: "none", color: "#64748b",
            cursor: "pointer", fontSize: 20, padding: 4
          }}>☰</button>
          <div style={{ flex: 1 }}>
            <div style={{ fontWeight: 700, fontSize: 16 }}>Smart AI Assistant</div>
            <div style={{ fontSize: 12, color: "#64748b" }}>
              <span style={{ color: "#22c55e", marginRight: 6 }}>●</span>
              Powered by Gemini AI • College Final Year Project
            </div>
          </div>
          {isSpeaking && (
            <button onClick={stopSpeaking} style={{
              background: "rgba(239,68,68,0.2)", border: "1px solid rgba(239,68,68,0.4)",
              borderRadius: 8, padding: "6px 12px", color: "#f87171",
              cursor: "pointer", fontSize: 12
            }}>⏹ Stop</button>
          )}
        </div>

        {/* API Key Modal */}
        {showKeyInput && (
          <div style={{
            position: "absolute", inset: 0, background: "rgba(0,0,0,0.7)",
            display: "flex", alignItems: "center", justifyContent: "center", zIndex: 100
          }}>
            <div style={{
              background: "#1e1e2e", borderRadius: 16, padding: 32, width: 420,
              border: "1px solid rgba(99,102,241,0.3)"
            }}>
              <div style={{ fontSize: 20, fontWeight: 700, marginBottom: 8 }}>🔑 Gemini API Key</div>
              <div style={{ fontSize: 13, color: "#64748b", marginBottom: 20 }}>
                Free key: <a href="https://aistudio.google.com/app/apikey" target="_blank" style={{ color: "#6366f1" }}>aistudio.google.com</a>
              </div>
              <input type="password" value={apiKey} onChange={e => setApiKey(e.target.value)}
                placeholder="AIza..." style={{
                  width: "100%", background: "rgba(255,255,255,0.06)",
                  border: "1px solid rgba(255,255,255,0.1)", borderRadius: 10,
                  padding: "12px 16px", color: "#e2e8f0", fontSize: 14,
                  marginBottom: 16, boxSizing: "border-box"
                }} />
              <div style={{ display: "flex", gap: 10 }}>
                <button onClick={saveKey} style={{
                  flex: 1, background: "linear-gradient(135deg, #6366f1, #8b5cf6)",
                  border: "none", borderRadius: 10, padding: 12,
                  color: "#fff", fontWeight: 600, cursor: "pointer"
                }}>Save & Continue</button>
                <button onClick={() => setShowKeyInput(false)} style={{
                  flex: 1, background: "rgba(255,255,255,0.06)",
                  border: "1px solid rgba(255,255,255,0.1)", borderRadius: 10, padding: 12,
                  color: "#94a3b8", cursor: "pointer"
                }}>Cancel</button>
              </div>
            </div>
          </div>
        )}

        {/* Messages */}
        <div style={{ flex: 1, overflowY: "auto", padding: "24px 32px" }}>
          {messages.map((msg, i) => <Message key={i} msg={msg} />)}
          {loading && (
            <div style={{ display: "flex", marginBottom: 16 }}>
              <div style={{
                width: 36, height: 36, borderRadius: "50%",
                background: "linear-gradient(135deg, #6366f1, #8b5cf6)",
                display: "flex", alignItems: "center", justifyContent: "center",
                fontSize: 16, marginRight: 10
              }}>🤖</div>
              <div style={{
                background: "rgba(255,255,255,0.07)",
                borderRadius: "18px 18px 18px 4px",
                border: "1px solid rgba(255,255,255,0.1)"
              }}><TypingIndicator /></div>
            </div>
          )}
          <div ref={bottomRef} />
        </div>

        {/* INPUT BAR */}
        <div style={{ padding: "16px 32px 24px", borderTop: "1px solid rgba(255,255,255,0.08)" }}>
          <div style={{
            display: "flex", gap: 10, alignItems: "flex-end",
            background: "rgba(255,255,255,0.06)",
            border: "1px solid rgba(255,255,255,0.12)",
            borderRadius: 16, padding: "10px 14px"
          }}>
            <textarea ref={inputRef} value={input}
              onChange={e => setInput(e.target.value)}
              onKeyDown={handleKey}
              placeholder="Ask Nova anything..."
              style={{
                flex: 1, background: "transparent", border: "none",
                color: "#e2e8f0", fontSize: 14, resize: "none",
                minHeight: 24, maxHeight: 120, lineHeight: 1.6,
                fontFamily: "'Segoe UI', sans-serif"
              }} rows={1} />

            <div style={{ display: "flex", gap: 6, alignItems: "center" }}>

              {/* 🎤 Voice Input */}
              <button
                onClick={isListening ? stopListening : startListening}
                title={isListening ? "Sunna band karo" : "Voice se bolo"}
                style={{
                  background: isListening ? "rgba(239,68,68,0.3)" : "transparent",
                  border: isListening ? "1px solid rgba(239,68,68,0.6)" : "none",
                  borderRadius: 8, color: isListening ? "#f87171" : "#64748b",
                  cursor: "pointer", fontSize: 18, padding: "4px 6px",
                  animation: isListening ? "pulse 1s infinite" : "none"
                }}>🎤</button>

              {/* 🖼️ Image Upload */}
              <button onClick={() => fileInputRef.current.click()}
                title="Image upload karo"
                style={{
                  background: "transparent", border: "none",
                  color: "#64748b", cursor: "pointer", fontSize: 18, padding: "4px 6px"
                }}>🖼️</button>

              {/* 🎥 Video Upload */}
              <button onClick={() => videoFileRef.current.click()}
                title="Video upload karo"
                style={{
                  background: "transparent", border: "none",
                  color: "#64748b", cursor: "pointer", fontSize: 18, padding: "4px 6px"
                }}>🎥</button>

              {/* 📷 Live Camera */}
              <button onClick={openCamera}
                title="Live camera kholo"
                style={{
                  background: "transparent", border: "none",
                  color: "#64748b", cursor: "pointer", fontSize: 18, padding: "4px 6px"
                }}>📷</button>

              {/* ➤ Send */}
              <button onClick={() => sendMessage()} disabled={loading || !input.trim()} style={{
                background: loading || !input.trim()
                  ? "rgba(99,102,241,0.3)"
                  : "linear-gradient(135deg, #6366f1, #8b5cf6)",
                border: "none", borderRadius: 10, width: 40, height: 40,
                color: "#fff", cursor: loading || !input.trim() ? "not-allowed" : "pointer",
                fontSize: 18, display: "flex", alignItems: "center", justifyContent: "center"
              }}>➤</button>
            </div>
          </div>

          {/* Status indicators */}
          <div style={{ display: "flex", justifyContent: "space-between", marginTop: 8 }}>
            <div style={{ fontSize: 11, color: "#334155" }}>
              Smart AI Assistant • Final Year Project • Powered by Google Gemini
            </div>
            <div style={{ fontSize: 11, display: "flex", gap: 10 }}>
              {isListening && <span style={{ color: "#f87171", animation: "pulse 1s infinite" }}>🎤 Sun raha hoon...</span>}
              {isSpeaking && <span style={{ color: "#a5b4fc", animation: "pulse 1s infinite" }}>🔊 Bol raha hoon...</span>}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
